/* 4. Slide to Unlock confirmation Styles */
.slide-unlock-container {
  width: 100%;
}

.slide-track {
  width: 100%;
  height: 56px;
  background-color: #f1f5f9;
  border: 1px solid #cbd5e1;
  border-radius: 28px;
  position: relative;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

.slide-handle {
  width: 48px; height: 48px;
  background-color: #6366f1;
  color: #ffffff;
  border-radius: 50%;
  position: absolute;
  left: 4px; top: 3px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: grab;
  z-index: 10;
  box-shadow: 0 3px 6px rgba(99, 102, 241, 0.3);
  transition: transform 0.35s cubic-bezier(0.16, 1, 0.3, 1);
}

.slide-label {
  font-size: 14px;
  font-weight: 500;
  color: #64748b;
  z-index: 5;
  pointer-events: none;
}

.slide-track.unlocked {
  background-color: rgba(16, 185, 129, 0.1);
  border-color: #10b981;
}

.slide-track.unlocked .slide-handle {
  background-color: #10b981;
}

.slide-track.unlocked .slide-label {
  color: #10b981;
  font-weight: 700;
}
